import{_ as t,o,c as d,a2 as s}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"Scheduling","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/schedule.md","filePath":"en/guide/schedule.md","lastUpdated":1783223243000}'),a={name:"en/guide/schedule.md"};function i(r,e,n,c,l,h){return o(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h1><p>Every schedule in <code>config.json</code> is expressed with the same object:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;schedule&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;every&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;ISO8601 duration&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;HH:MM&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><ul><li><strong><code>every</code></strong> — an ISO8601 duration meaning &quot;how often&quot;.</li><li><strong><code>at</code></strong> — optional, <code>HH:MM</code> (24-hour, zero-padded), the time of day to run. <strong>Only meaningful when the period is ≥ 1 day</strong>.</li></ul><p>The <code>timer_daemon</code> reads <code>config.json</code> directly and converts it into an in-memory schedule table — no intermediate derived files, and you never touch cron expressions.</p><h2 id="rules-for-every" tabindex="-1">Rules for <code>every</code> <a class="header-anchor" href="#rules-for-every" aria-label="Permalink to &quot;Rules for `every`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Meaning</th><th><code>every</code> form</th><th><code>at</code> required</th></tr></thead><tbody><tr><td>Every N minutes</td><td><code>PT2M</code> (every 2 min)</td><td>No</td></tr><tr><td>Every N hours</td><td><code>PT4H</code> (every 4 hours)</td><td>No</td></tr><tr><td>Every N days</td><td><code>P1D</code> / <code>P3D</code></td><td><strong>Yes</strong> (specify the time)</td></tr><tr><td>Every N weeks</td><td><code>P1W</code> / <code>P2W</code></td><td><strong>Yes</strong></td></tr></tbody></table><p>Fixed format:</p><ul><li><code>PT&lt;positive int&gt;M</code> / <code>PT&lt;positive int&gt;H</code> — time component (minutes / hours).</li><li><code>P&lt;positive int&gt;D</code> / <code>P&lt;positive int&gt;W</code> — date component (days / weeks).</li></ul><p>The number must be a <strong>positive integer ≥ 1</strong>.</p><h2 id="two-kinds-of-schedules" tabindex="-1">Two kinds of schedules <a class="header-anchor" href="#two-kinds-of-schedules" aria-label="Permalink to &quot;Two kinds of schedules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kind</th><th>Fields</th><th>Trait</th></tr></thead><tbody><tr><td><strong>Frequency</strong></td><td><code>app_clean.detect_schedule</code>, <code>suppress.detect_schedule</code>, <code>gc.schedule</code></td><td>Minute/hour intervals only, <strong>no <code>at</code></strong></td></tr><tr><td><strong>Timed</strong></td><td><code>app_clean.other.schedule</code>, <code>empty_folder.schedule</code></td><td>An interval (every N days/weeks) plus a time <code>at</code></td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><table tabindex="0"><thead><tr><th><code>every</code> / <code>at</code></th><th>Meaning</th></tr></thead><tbody><tr><td><code>PT2M</code></td><td>Every 2 minutes</td></tr><tr><td><code>PT4H</code></td><td>Every 4 hours</td></tr><tr><td><code>P1D</code> + <code>03:00</code></td><td>Daily at 03:00</td></tr><tr><td><code>P3D</code> + <code>03:00</code></td><td>Every 3 days at 03:00</td></tr><tr><td><code>P1W</code> + <code>04:00</code></td><td>Once a week at 04:00</td></tr></tbody></table><h2 id="key-constraints" tabindex="-1">Key constraints <a class="header-anchor" href="#key-constraints" aria-label="Permalink to &quot;Key constraints&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Must follow</p><ol><li><strong>Don&#39;t set <code>at</code> on frequency schedules</strong> (it&#39;s ignored); <strong>timed schedules (days/weeks) must set <code>at</code></strong>, otherwise they default to <code>00:00</code>.</li><li><strong><code>every</code> must be a positive integer ≥ 1</strong>. On a parse failure the job is skipped — that feature won&#39;t run.</li><li><strong>Changes take effect without a reboot</strong> — use an atomic write (write a temp file, then <code>mv</code> over it).</li></ol></div><h2 id="how-multi-day-periods-work" tabindex="-1">How multi-day periods work <a class="header-anchor" href="#how-multi-day-periods-work" aria-label="Permalink to &quot;How multi-day periods work&quot;">​</a></h2><p>Cron expressions can&#39;t precisely express &quot;every N days&quot;, so for periods ≥ 1 day the module uses <strong>timestamp gating</strong>: the daemon fires at the <code>at</code> time each day but, before running, checks the last-run timestamp in <code>cron/state</code> and skips if less than N days have passed. <code>cron/state</code> is maintained automatically — you only write the <code>schedule</code> object in <code>config.json</code>.</p>',18)])])}const g=t(a,[["render",i]]);export{p as __pageData,g as default};
